import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quoting a premium", () => {
    it.todo("should calculate base premium for a single sword with first-insurance surcharge and processing fee");
    it.todo("should calculate base premium for a single amulet");
    it.todo("should sum premiums for multiple items");
    it.todo("should calculate base premium for a single component");
    it.todo("should apply building block pricing for 3 alike components");
    it.todo("should apply 50% cursed surcharge to a cursed item");
    it.todo("should apply 30% surcharge for highly enchanted item (enchantment >= 5)");
    it.todo("should apply both cursed and enchantment surcharges");
    it.todo("should apply 20% loyalty discount for long-standing customer (>= 2 years)");
    it.todo("should apply 15% discount on second contract instead of first-insurance surcharge");
    it.todo("should round amounts in MHPCO's favor");
  });

  describe("Processing a claim", () => {
    it.todo("should apply 100G deductible to a claim");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse at 50% for items with enchantment >= 8");
    it.todo("should fully reimburse damage to dragon material items");
    it.todo("should reduce remaining cap across multiple claims on the same policy");
  });
});

