interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

export function processScenario(scenario: Scenario): { results: unknown[] } {
  const results = scenario.steps.map((step) => {
    const basePremium = BASE_PREMIUMS[step.items[0].type];
    const premium = Math.ceil(basePremium * 1.1) + 5;
    return { premium };
  });
  return { results };
}

