      // Damage: 1400G - 100G deductible = 1300G
      // Capped at 1200G → payout = 1200G
      // Remaining cap: 1200 - 1200 = 0G
      expect(result.results[1]).toEqual({ payout: 1200, remainingCap: 0 });
